from dataclasses import dataclass, field
from typing import List, Dict, Optional, Tuple
import math


@dataclass
class CacheConfig:
    total_size: int
    block_size: int
    associativity: int
    address_bits: int = 32

    @property
    def num_blocks(self) -> int:
        return self.total_size // self.block_size

    @property
    def num_sets(self) -> int:
        return self.num_blocks // self.associativity

    @property
    def offset_bits(self) -> int:
        return int(math.log2(self.block_size))

    @property
    def index_bits(self) -> int:
        return int(math.log2(self.num_sets))

    @property
    def tag_bits(self) -> int:
        return self.address_bits - self.offset_bits - self.index_bits


class CacheSimulator:
    def __init__(self, config: CacheConfig):
        self.config = config
        self.sets: List[List[Dict]] = [
            [{'valid': False, 'tag': 0, 'lru': 0}
             for _ in range(config.associativity)]
            for _ in range(config.num_sets)
        ]
        self.lru_counter = 0
        self.hits = 0
        self.misses = 0
        self.compulsory_misses = 0
        self.capacity_misses = 0
        self.conflict_misses = 0
        self.seen_blocks: set = set()
        self.fully_assoc_tags: list = []
        self.fully_assoc_capacity = config.num_blocks

    def _decompose(self, address: int) -> Tuple[int, int, int]:
        offset_mask = (1 << self.config.offset_bits) - 1
        index_mask = (1 << self.config.index_bits) - 1
        offset = address & offset_mask
        index = (address >> self.config.offset_bits) & index_mask
        tag = address >> (self.config.offset_bits + self.config.index_bits)
        return tag, index, offset

    def _block_addr(self, address: int) -> int:
        return address >> self.config.offset_bits

    def _lookup_set(self, set_idx: int, tag: int) -> Optional[int]:
        for way, line in enumerate(self.sets[set_idx]):
            if line['valid'] and line['tag'] == tag:
                return way
        return None

    def _find_victim(self, set_idx: int) -> int:
        cache_set = self.sets[set_idx]
        for i, line in enumerate(cache_set):
            if not line['valid']:
                return i
        min_lru = cache_set[0]['lru']
        min_idx = 0
        for i, line in enumerate(cache_set):
            if line['lru'] < min_lru:
                min_lru = line['lru']
                min_idx = i
        return min_idx

    def _classify_miss(self, block_addr: int) -> str:
        if block_addr not in self.seen_blocks:
            return 'compulsory'
        if block_addr not in self.fully_assoc_tags:
            return 'capacity'
        return 'conflict'

    def _update_fully_assoc(self, block_addr: int) -> None:
        if block_addr in self.fully_assoc_tags:
            self.fully_assoc_tags.remove(block_addr)
        elif len(self.fully_assoc_tags) >= self.fully_assoc_capacity:
            self.fully_assoc_tags.pop(0)
        self.fully_assoc_tags.append(block_addr)

    def access(self, address: int) -> bool:
        tag, index, offset = self._decompose(address)
        block_addr = self._block_addr(address)

        way = self._lookup_set(index, tag)
        if way is not None:
            # Hit
            self.hits += 1
            self.lru_counter += 1
            self.sets[index][way]['lru'] = self.lru_counter
            self._update_fully_assoc(block_addr)
            return True
        else:
            # Miss
            self.misses += 1
            miss_type = self._classify_miss(block_addr)
            if miss_type == 'compulsory':
                self.compulsory_misses += 1
            elif miss_type == 'capacity':
                self.capacity_misses += 1
            else:
                self.conflict_misses += 1

            self.seen_blocks.add(block_addr)

            victim = self._find_victim(index)
            self.lru_counter += 1
            self.sets[index][victim] = {
                'valid': True,
                'tag': tag,
                'lru': self.lru_counter
            }

            self._update_fully_assoc(block_addr)
            return False

    def process_trace(self, addresses: List[int]) -> Dict:
        for addr in addresses:
            self.access(addr)
        total = self.hits + self.misses
        return {
            'total_accesses': total,
            'hits': self.hits,
            'misses': self.misses,
            'hit_rate': self.hits / total if total > 0 else 0.0,
            'compulsory': self.compulsory_misses,
            'capacity': self.capacity_misses,
            'conflict': self.conflict_misses
        }

from typing import List, Dict, Tuple
import math


def naive_matmul(A: List[List[float]], B: List[List[float]]) -> List[List[float]]:
    n = len(A)
    C = [[0.0] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            for k in range(n):
                C[i][j] += A[i][k] * B[k][j]
    return C


def tiled_matmul(A: List[List[float]], B: List[List[float]],
                  tile_size: int) -> List[List[float]]:
    n = len(A)
    C = [[0.0] * n for _ in range(n)]
    for ii in range(0, n, tile_size):
        for jj in range(0, n, tile_size):
            for kk in range(0, n, tile_size):
                for i in range(ii, min(ii + tile_size, n)):
                    for j in range(jj, min(jj + tile_size, n)):
                        for k in range(kk, min(kk + tile_size, n)):
                            C[i][j] += A[i][k] * B[k][j]
    return C


def generate_naive_trace(n: int, elem_size: int = 8) -> List[int]:
    base_a = 0
    base_b = n * n * elem_size
    base_c = 2 * n * n * elem_size
    trace = []
    for i in range(n):
        for j in range(n):
            for k in range(n):
                trace.append(base_a + (i * n + k) * elem_size)  # A[i][k]
                trace.append(base_b + (k * n + j) * elem_size)  # B[k][j]
                trace.append(base_c + (i * n + j) * elem_size)  # C[i][j]
    return trace


def generate_tiled_trace(n: int, tile_size: int,
                          elem_size: int = 8) -> List[int]:
    base_a = 0
    base_b = n * n * elem_size
    base_c = 2 * n * n * elem_size
    trace = []
    for ii in range(0, n, tile_size):
        for jj in range(0, n, tile_size):
            for kk in range(0, n, tile_size):
                for i in range(ii, min(ii + tile_size, n)):
                    for j in range(jj, min(jj + tile_size, n)):
                        for k in range(kk, min(kk + tile_size, n)):
                            trace.append(base_a + (i * n + k) * elem_size)
                            trace.append(base_b + (k * n + j) * elem_size)
                            trace.append(base_c + (i * n + j) * elem_size)
    return trace


def simulate_cache(trace: List[int], cache_size: int,
                    block_size: int, associativity: int) -> Dict:
    num_blocks = cache_size // block_size
    num_sets = num_blocks // associativity
    offset_bits = int(math.log2(block_size))
    index_bits = int(math.log2(num_sets)) if num_sets > 1 else 0
    index_mask = (1 << index_bits) - 1 if index_bits > 0 else 0

    # Each set: list of (tag, lru_counter)
    sets = [[None] * associativity for _ in range(max(num_sets, 1))]
    lru = [[0] * associativity for _ in range(max(num_sets, 1))]
    counter = 0
    hits = 0
    misses = 0

    for addr in trace:
        block_addr = addr >> offset_bits
        if index_bits > 0:
            set_idx = (addr >> offset_bits) & index_mask
            tag = addr >> (offset_bits + index_bits)
        else:
            set_idx = 0
            tag = block_addr

        counter += 1
        # Check for hit
        hit = False
        for w in range(associativity):
            if sets[set_idx][w] == tag:
                hits += 1
                lru[set_idx][w] = counter
                hit = True
                break

        if not hit:
            misses += 1
            # Find victim: prefer empty slot, then LRU
            victim = 0
            min_lru = lru[set_idx][0]
            for w in range(associativity):
                if sets[set_idx][w] is None:
                    victim = w
                    break
                if lru[set_idx][w] < min_lru:
                    min_lru = lru[set_idx][w]
                    victim = w
            sets[set_idx][victim] = tag
            lru[set_idx][victim] = counter

    total = hits + misses
    return {
        'hits': hits,
        'misses': misses,
        'total': total,
        'hit_rate': hits / total if total > 0 else 0.0
    }


def compare_cache_performance(n: int, tile_size: int,
                                cache_size: int = 4096,
                                block_size: int = 64,
                                associativity: int = 4) -> Dict:
    naive_trace = generate_naive_trace(n)
    tiled_trace = generate_tiled_trace(n, tile_size)

    naive_result = simulate_cache(naive_trace, cache_size, block_size, associativity)
    tiled_result = simulate_cache(tiled_trace, cache_size, block_size, associativity)

    return {
        'n': n,
        'tile_size': tile_size,
        'cache_size': cache_size,
        'naive_hit_rate': naive_result['hit_rate'],
        'tiled_hit_rate': tiled_result['hit_rate'],
        'improvement': tiled_result['hit_rate'] - naive_result['hit_rate']
    }

from typing import List, Dict
import math


class RooflineAnalyzer:
    def __init__(self, peak_flops: float, peak_bandwidth: float):
        self.peak_flops = peak_flops
        self.peak_bandwidth = peak_bandwidth

    @property
    def ridge_point(self) -> float:
        return self.peak_flops / self.peak_bandwidth

    def attainable_performance(self, arithmetic_intensity: float) -> float:
        return min(self.peak_flops, arithmetic_intensity * self.peak_bandwidth)

    def classify(self, arithmetic_intensity: float) -> str:
        if arithmetic_intensity >= self.ridge_point:
            return 'compute-bound'
        return 'memory-bound'

    def analyze_kernels(self, kernels: List[Dict]) -> List[Dict]:
        results = []
        for k in kernels:
            ai = k['arithmetic_intensity']
            perf = self.attainable_performance(ai)
            classification = self.classify(ai)
            efficiency = perf / self.peak_flops * 100
            results.append({
                'name': k['name'],
                'arithmetic_intensity': ai,
                'attainable_flops': perf,
                'classification': classification,
                'efficiency_pct': round(efficiency, 1),
                'ridge_point': self.ridge_point
            })
        return results

    @staticmethod
    def compute_vector_add_ai(n: int, elem_bytes: int = 8) -> float:
        flops = n  # n additions
        bytes_transferred = 3 * n * elem_bytes  # Read A, B; Write C
        return flops / bytes_transferred

    @staticmethod
    def compute_dot_product_ai(n: int, elem_bytes: int = 8) -> float:
        flops = 2 * n  # n multiplies + n adds (approximately)
        bytes_transferred = 2 * n * elem_bytes  # Read A, B
        return flops / bytes_transferred

    @staticmethod
    def compute_matvec_ai(n: int, elem_bytes: int = 8) -> float:
        flops = 2 * n * n  # n^2 multiplies + n^2 adds (approximately)
        bytes_transferred = (n * n + 2 * n) * elem_bytes  # A + x + y
        return flops / bytes_transferred

    @staticmethod
    def compute_matmul_ai(n: int, elem_bytes: int = 8) -> float:
        flops = 2 * n * n * n  # n^3 multiplies + n^3 adds
        bytes_transferred = 3 * n * n * elem_bytes  # A + B + C
        return flops / bytes_transferred
